  DCL-DS st_stat LIKEDS(st_stat_t) INZ;

/COPY QIFS,IFS1006
  // ---------------------------------------------------------

  // Get the size of the IFS file  and ...
if   stat(%trim(i_path): %addr(st_stat)) = RC_ERROR;
