   if (isPresent = 1);
  // then pass back the message
      o_msg = msg;
   endif;
else;
  // else send message
   if (msg.ID <> cMsg_ID_OK);
      f_sndPgmMsg(msg: cMsg_Prv);
   endif;
endif;

return    fileSize;


END-PROC;

