  i_path LIKE(ifs_path_t) CONST;
END-PR;

//  Retrieves the directory name from a given path name.
DCL-PR f_rtvIfsDirFromPath LIKE(ifs_path_t) EXTPROC('IFSR01_f_rtvIfsDirFromPath');
