  o_msg      LIKE(msg_t) OPTIONS(*NOPASS: *OMIT);
END-PR;

//  Closes an IFS file that was opened with the f_opnIfsFile-function.
DCL-PR f_closeIfsFile INT(10) EXTPROC('IFSR01_f_closeIfsFile');
