  i_pBuffer POINTER OPTIONS(*STRING) CONST;
  i_length  INT(10) CONST;
  o_msg     LIKE(msg_t) OPTIONS(*NOPASS: *OMIT);
END-PR;

//  Writes line to an IFS file.
DCL-PR f_writeLineIfsFile INT(10) EXTPROC('IFSR01_f_writeLineIfsFile');
